import org.dom4j.io.SAXReader;
import org.xml.sax.SAXException;
import org.w3c.dom.Document;

/**
 * XML configuration parsing service with security-hardened parsing capabilities.
 * Converts user-uploaded XML files into W3C DOM Documents for further processing.
 */
public class ConfigService {

    /**
     * Loads and parses an XML configuration file into a W3C DOM Document.
     * 
     * @param configPath Path to the XML configuration file
     * @return Parsed W3C DOM Document object
     * @throws IllegalArgumentException if configPath is null or empty
     * @throws RuntimeException for XML parsing errors, I/O failures, or security configuration issues
     */
    public Document loadConfig(String configPath) {
        // Validate input path
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path must not be null or empty");
        }

        SAXReader saxReader = new SAXReader();

        // Harden parser against XXE attacks and other XML vulnerabilities
        try {
            // Disable DOCTYPE declarations entirely to prevent XXE and billion-laughs attacks
            saxReader.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            // Additional layered security (defense in depth)
            saxReader.setFeature("http://xml.org/sax/features/external-general-entities", false);
            saxReader.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            saxReader.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        } catch (SAXException e) {
            throw new RuntimeException("Critical failure: XML parser security configuration failed. Aborting to prevent vulnerabilities.", e);
        }

        try {
            // Parse XML into DOM4J document
            org.dom4j.Document dom4jDoc = saxReader.read(configPath);

            // Convert to standard W3C DOM Document
            DOMWriter domWriter = new DOMWriter();
            return domWriter.write(dom4jDoc);
        } catch (DocumentException e) {
            // Unified error handling for all parsing failures (invalid XML, file not found, IO errors)
            throw new RuntimeException("XML configuration parsing failed. Verify file exists, is accessible, and contains well-formed XML.", e);
        }
    }
}
